mapper.select:
	/*
		 SQL ID : SysAuthGrpDAO.selectListAuthGrp
		 설  명 : 시스템 권한그룹정보 조회
 	*/	
	SELECT * 
	  FROM TB_LMS_AUTHRT_GRP A
	 WHERE ORG_ID = #{orgId}
	   AND MENU_TYCD = #{menuType}

	   AND USER_AUTHRT_ID != 'ADMIN'

	 ORDER BY AUTHRT_GRP_SEQ

	/*
		 SQL ID : SysAuthGrpDAO.selectListAuthGrp
		 설  명 : 시스템 권한그룹정보 조회
 	*/	
	SELECT * 
	  FROM TB_LMS_AUTHRT_GRP A
	 WHERE ORG_ID = #{orgId}
	   AND MENU_TYCD = #{menuType}

	   AND USER_AUTHRT_ID != 'ADMIN'

	 ORDER BY AUTHRT_GRP_SEQ

/* SQL ID : SysAuthGrpDAO.list 설 명 : 시스템 권한의 전체 목록 */ SELECT MENU_TYCD as menuType , USER_AUTHRT_ID as authGrpCd , AUTHRT_GRPNM as authGrpNm , USEYN as useYn , AUTHRT_GRP_EXPLN as authGrpDesc , AUTHRT_GRP_SEQ as authGrpOdr , RGTR_ID as rgtrId , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = RGTR_ID) AS regNm , FRST_INQ_DTTM as regDttm , MDFR_ID as mdfrId , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = MDFR_ID) AS modNm , MOD_DTTM as modDttm FROM TB_SYS_AUTH_GRP WHERE MENU_TYCD = #{menuType}
AND USEYN = #{useYn}
ORDER BY AUTHRT_GRP_SEQ

mapper.insert:
	/*
		 SQL ID : SysAuthGrpDAO.insert
		 설  명 : 시스템 권한의 정보 등록
 	*/
	INSERT INTO TB_SYS_AUTH_GRP (
	       MENU_TYCD
	     , USER_AUTHRT_ID
	     , AUTHRT_GRPNM
	     , USEYN
	     , AUTHRT_GRP_EXPLN
	     , AUTHRT_GRP_SEQ
	     , RGTR_ID
	     , FRST_INQ_DTTM
	     , MDFR_ID
	     , MOD_DTTM
	) VALUES ( 
	       #{menuType}
	     , #{authGrpCd}
	     , #{authGrpNm}
	     , #{useYn}
	     , #{authGrpDesc}
	     , ( SELECT IFNULL(MAX(A.AUTHRT_GRP_SEQ),0)+1
	           FROM TB_SYS_AUTH_GRP A
	          WHERE A.MENU_TYCD = #{menuType} )
	     , #{rgtrId}
	     , DATE_FORMAT(NOW()-1, '%Y%m%d%H%i%s')
	     , #{mdfrId}
	     , DATE_FORMAT(NOW()-1, '%Y%m%d%H%i%s')
	)

mapper.update:
	/*
		 SQL ID : SysAuthGrpDAO.update
		 설  명 : 시스템 권한의 정보 수정
 	*/
	UPDATE TB_SYS_AUTH_GRP
	   SET USEYN = #{useYn}

	   	 ,AUTHRT_GRPNM = #{authGrpNm} 


	     , AUTHRT_GRP_EXPLN = #{authGrpDesc}


	     , AUTHRT_GRP_SEQ = #{authGrpOdr}

	     , MDFR_ID = #{mdfrId}
	     , MOD_DTTM = DATE_FORMAT(NOW()-1, '%Y%m%d%H%i%s')
	 WHERE MENU_TYCD = #{menuType}
	   AND USER_AUTHRT_ID = #{authGrpCd}

mapper.delete:
	/*
		 SQL ID : SysAuthGrpDAO.delete
		 설  명 : 시스템 권한의 정보 삭제
 	*/
	DELETE FROM TB_SYS_AUTH_GRP
	 WHERE MENU_TYCD = #{menuType}
	   AND USER_AUTHRT_ID = #{authGrpCd}
